'use client';

import { useReducedMotion } from 'framer-motion';

const capabilities = [
  'Brand Strategy',
  'Web Design',
  'Mobile Apps',
  'UI/UX Design',
  'Digital Marketing',
  'SEO',
  'AI Automation',
  'Cloud Architecture',
  'E-commerce',
  'Content Strategy',
  'Performance Marketing',
  'DevOps',
  'Arabic Localisation',
  'Market Research',
  'Data & Analytics',
];

function MarqueeRow({ reversed = false }: { reversed?: boolean }) {
  const items = [...capabilities, ...capabilities];
  return (
    <div className="overflow-hidden">
      <div
        className={`flex gap-8 whitespace-nowrap ${reversed ? 'animate-[marquee_40s_linear_infinite_reverse]' : 'animate-marquee'}`}
        aria-hidden="true"
      >
        {items.map((cap, i) => (
          <span key={i} className="flex items-center gap-8">
            <span className="font-display text-4xl md:text-5xl font-black uppercase text-white/20">
              {cap}
            </span>
            <span className="text-[#0000FF] font-display text-4xl font-black">·</span>
          </span>
        ))}
      </div>
    </div>
  );
}

export function CapabilitiesMarquee() {
  const prefersReducedMotion = useReducedMotion();

  if (prefersReducedMotion) {
    return (
      <section className="bg-black py-16 overflow-hidden border-y border-white/5" aria-label="Capabilities">
        <div className="container-site">
          <div className="flex flex-wrap gap-3">
            {capabilities.map((cap) => (
              <span
                key={cap}
                className="font-display text-xl font-black uppercase text-white/20 px-2"
              >
                {cap} <span className="text-[#0000FF]">·</span>
              </span>
            ))}
          </div>
        </div>
      </section>
    );
  }

  return (
    <section
      className="bg-black py-12 overflow-hidden border-y border-white/5"
      aria-label="Capabilities"
    >
      <div className="flex flex-col gap-6 py-2">
        <MarqueeRow />
        <MarqueeRow reversed />
      </div>
    </section>
  );
}
